import{_ as s,c as r,o as t,ae as c}from"./chunks/framework.B7Y1jjX-.js";const N=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/公共技术/SQL/数据库实验.md","filePath":"notes/公共技术/SQL/数据库实验.md"}'),d={name:"notes/公共技术/SQL/数据库实验.md"};function _(u,e,o,n,i,E){return t(),r("div",null,[...e[0]||(e[0]=[c('<h4 id="_20道版本" tabindex="-1">20道版本 <a class="header-anchor" href="#_20道版本" aria-label="Permalink to &quot;20道版本&quot;">​</a></h4><p>1 SELECT s.name AS student_name, c.course_name, g.score<br> FROM students s<br> JOIN grades g ON s.student_id = g.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.teacher_name = &#39;王刚&#39; AND g.score &gt; 90;</p><p>2 SELECT DISTINCT s.name AS student_name, s.college<br> FROM students s<br> JOIN grades g ON s.student_id = g.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.teacher_name = &#39;王刚&#39;;</p><p>3 SELECT s.student_id, s.name<br> FROM students s<br> LEFT JOIN enrollments e ON s.student_id = e.student_id<br> LEFT JOIN courses c ON e.course_id = c.course_id AND c.course_name = &#39;软件工程&#39;<br> WHERE c.course_name IS NULL;</p><p>4 SELECT student_id<br> FROM enrollments<br> GROUP BY student_id<br> HAVING COUNT(course_id) &gt;= 2;</p><p>5 SELECT s.name AS student_name, g.score<br> FROM students s<br> JOIN grades g ON s.student_id = g.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.course_name = &#39;经济学&#39; AND g.score &lt; 60;</p><p>6 SELECT DISTINCT e1.student_id<br> FROM enrollments e1<br> JOIN enrollments e2 ON e1.course_id = e2.course_id<br> WHERE e2.student_id = &#39;T06&#39; AND e1.student_id &lt;&gt; &#39;T06&#39;;</p><p>7 SELECT s.name AS student_name, s.college<br> FROM students s<br> JOIN enrollments e ON s.student_id = e.student_id<br> WHERE e.course_id IN (&#39;C3&#39;, &#39;C4&#39;)<br> GROUP BY s.student_id, s.name, s.college<br> HAVING COUNT(DISTINCT e.course_id) = 2;</p><p>8 SELECT c.course_id, c.course_name<br> FROM courses c<br> LEFT JOIN enrollments e ON c.course_id = e.course_id AND e.student_id = (<br> SELECT student_id FROM students WHERE name = &#39;王石&#39;<br> )<br> WHERE e.student_id IS NULL;</p><p>9 SELECT c.course_id<br> FROM courses c<br> LEFT JOIN enrollments e ON c.course_id = e.course_id<br> WHERE e.course_id IS NULL;</p><p>10 SELECT s.name<br> FROM students s<br> JOIN enrollments e ON s.student_id = e.student_id<br> GROUP BY s.student_id, s.name<br> HAVING COUNT(DISTINCT e.course_id) = (SELECT COUNT(*) FROM courses);</p><p>11 SELECT s.college AS 学院名称, AVG(g.score) AS 平均分<br> FROM grades g<br> JOIN students s ON g.student_id = s.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.course_name = &#39;经济学&#39;<br> GROUP BY s.college<br> ORDER BY 平均分 DESC;</p><p>12 SELECT s.name AS 姓名, s.college AS 学院名称, g.score AS 成绩<br> FROM grades g<br> JOIN students s ON g.student_id = s.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.course_name = &#39;经济学&#39;<br> ORDER BY s.college, g.score DESC;</p><p>13 SELECT c.course_id AS 课程号, c.course_name AS 课程名, t.teacher_name AS 教师姓名<br> FROM courses c<br> JOIN course_teachers ct ON c.course_id = ct.course_id<br> JOIN teachers t ON ct.teacher_id = t.teacher_id<br> WHERE c.credit_hours BETWEEN 30 AND 45;</p><p>14 SELECT s.name AS 姓名<br> FROM grades g<br> JOIN students s ON g.student_id = s.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE c.course_name = &#39;经济学&#39;<br> AND g.score = (SELECT MAX(score) FROM grades WHERE course_id = (SELECT course_id FROM courses WHERE course_name = &#39;经济学&#39;));</p><p>15 SELECT c.course_id AS 课程号, c.course_name AS 课程名<br> FROM courses c<br> JOIN enrollments e ON c.course_id = e.course_id<br> GROUP BY c.course_id, c.course_name<br> HAVING COUNT(e.student_id) &gt; 5;</p><p>16 SELECT s.student_id AS 学号, s.name AS 姓名, c.course_name AS 课程名, g.score AS 成绩<br> FROM grades g<br> JOIN students s ON g.student_id = s.student_id<br> JOIN courses c ON g.course_id = c.course_id<br> WHERE g.semester = &#39;2024-1&#39;<br> AND g.score &gt; (<br> SELECT AVG(g2.score)<br> FROM grades g2<br> JOIN students s2 ON g2.student_id = s2.student_id<br> WHERE g2.semester = &#39;2024-1&#39; AND s2.class_id = s.class_id<br> )<br> ORDER BY s.student_id; -- Optional ordering by student_id</p><p>17 SELECT t.teacher_id AS 教师号, t.teacher_name AS 教师姓名, t.college AS 学院名称<br> FROM teachers t<br> JOIN teaching_records tr ON t.teacher_id = tr.teacher_id<br> WHERE tr.semester = &#39;2024-2&#39;<br> AND tr.credit_hours &gt; (<br> SELECT AVG(tr2.credit_hours)<br> FROM teaching_records tr2<br> JOIN teachers t2 ON tr2.teacher_id = t2.teacher_id<br> WHERE tr2.semester = &#39;2024-2&#39; AND t2.college = t.college<br> )<br> GROUP BY t.teacher_id, t.teacher_name, t.college;</p><p>18 SELECT s.student_id AS 学号, s.name AS 姓名, SUM(c.credit_hours * (g.score / 10 - 5)) AS 绩点总和 FROM students s JOIN grades g ON s.student_id = g.student_id JOIN courses c ON g.course_id = c.course_id WHERE s.college = &#39;计算机学院&#39; AND g.semester = &#39;2024-1&#39; GROUP BY s.student_id, s.name ORDER BY 绩点总和 DESC LIMIT 3;</p><p>19 SELECT s.student_id AS 学号, s.name AS 姓名, t.teacher_name AS 授课教师姓名, g.score AS 成绩, CASE WHEN g.score &gt;= 85 THEN &#39;优秀&#39; WHEN g.score &gt;= 75 THEN &#39;良好&#39; WHEN g.score &gt;= 60 THEN &#39;中等&#39; ELSE &#39;及格&#39; END AS 成绩等级 FROM grades g JOIN students s ON g.student_id = s.student_id JOIN courses c ON g.course_id = c.course_id JOIN teaching_records tr ON c.course_id = tr.course_id JOIN teachers t ON tr.teacher_id = t.teacher_id WHERE g.semester = &#39;2024-2&#39; AND c.course_name = &#39;数据库&#39;;</p><p>20 SELECT c.college AS 学院名称,<br> COUNT(c.course_id) AS 未开课数量<br> FROM courses c<br> LEFT JOIN (<br> SELECT course_id, COUNT(student_id) AS student_count<br> FROM enrollments<br> GROUP BY course_id<br> ) e ON c.course_id = e.course_id<br> WHERE e.student_count &lt;= 30 OR e.student_count IS NULL<br> GROUP BY c.college;</p>',21)])])}const a=s(d,[["render",_]]);export{N as __pageData,a as default};
